mapper.select:
/* com.shop.mapper.product.productContentList.selectProdContentList */
SELECT
      A.ID AS id
    , A.NEWS_TITLE AS newsTitle
    , A.NEWS_SUB_TITLE AS newsSubTitle
    , A.NEWS_CONTENTS AS newsContents
    , A.FILE_ID AS fileId
    , (SELECT COUNT(1) FROM TB_FILE_DET X WHERE X.FILE_ID = A.FILE_ID AND X.DEL_YN = 'N') AS imageCnt
    , (SELECT COUNT(1) FROM TB_CONTENTS_PRODUCT X WHERE X.CONTENTS_ID = A.ID AND DEL_YN = 'N') AS productCnt
FROM TB_CONTENTS A

    AND A.DEL_YN = 'N'
    AND A.NEWS_TYPE = #{filter.newsType}
    AND A.PARTNER_ID = #{filter.partnerId}

        AND A.NEWS_TITLE = #{filter.newsTitle}


        AND (
        A.ID > #{filter.lastId}
        )


ORDER BY A.ID
LIMIT #{pageRowCount} + 1;

mapper.update:
/* com.shop.mapper.product.productContentList.deleteProductContents */
UPDATE TB_CONTENTS
SET DEL_YN = 'Y'
  , UPD_USER = #{updUser}
  , UPD_TM = NOW()
WHERE ID = #{id}

mapper.select:
/* com.shop.mapper.product.productContentList.selectProductInfoList */ SELECT TPD.ID AS id , TP.ID AS prodId , P.ID AS partnerId , P.PARTNER_NM AS partnerNm , TP.PROD_CD AS prodCd , TP.PROD_TP AS prodTp , TP.PROD_NM AS prodNm , TPD.PRODUCT_DET_SIZE AS productDetSize , TPD.PRODUCT_DET_COLOR AS productDetColor , TP.ORG_AMT AS orgAmt , TP.SELL_AMT AS sellAmt , FN_GET_CODE('90010', TP.PROD_TP) prodTpNm FROM TB_PRODUCT_DET TPD JOIN TB_PRODUCT TP ON TP.ID = TPD.PRODUCT_ID AND TPD.DEL_YN = 'N' JOIN TB_PARTNER P ON P.ID = TP.PARTNER_ID AND P.DEL_YN = 'N'
AND TPD.DEL_YN = 'N'
AND TP.PROD_NM LIKE CONCAT('%' ,#{filter.prodNm} ,'%')
AND ( TPD.ID.ID > #{filter.lastId} )
GROUP BY TPD.ID,TP.ID, P.ID ORDER BY TP.ID LIMIT #{pageRowCount} + 1;
